#include <debugging>
#include <print>
#include <cstdlib>
#include <string_view>

// Отладочная проверка: в отладчике — пауза, иначе — abort
void debug_assert(bool condition, std::string_view msg) {
    if (!condition) {
        std::println(stderr, "Assertion failed: {}", msg);
        std::breakpoint_if_debugging(); // no-op без отладчика
        std::abort();
    }
}

int main() {
    // В обычном запуске: breakpoint_if_debugging() — no-op,
    // затем abort() завершит программу с сообщением выше.
    // В сеансе отладки: выполнение приостановится на строке breakpoint.
    debug_assert(1 + 1 == 2, "базовая арифметика"); // проходит
    // debug_assert(false, "тест"); // раскомментировать для демонстрации
}

#include <debugging>
#include <print>
#include <vector>
#include <string_view>

struct Request {
    int id;
    std::string_view path;
};

void handle(const Request& req) {
    // Детальная трассировка только когда подключён отладчик —
    // в продакшне эта ветка не выполняется совсем.
    if (std::is_debugger_present()) {
        std::println(stderr, "[trace] handle(): id={} path={}",
                     req.id, req.path);
    }

    if (req.path.empty()) {
        std::println(stderr, "[error] пустой путь запроса (id={})", req.id);
        // Дать отладчику шанс осмотреть стек до завершения
        std::breakpoint_if_debugging();
        std::abort();
    }

    std::println("OK: {}", req.path);
}

int main() {
    std::vector<Request> requests = {
        {1, "/api/users"},
        {2, "/api/orders"},
    };

    for (const auto& r : requests) {
        handle(r);
    }
}

