#include <format>
#include <print>
#include <array>

struct Matrix2x2 {
    std::array<std::array<double, 2>, 2> data;
};

template<> struct std::formatter<Matrix2x2> {
    constexpr auto parse(auto& ctx) { return ctx.begin(); }
    auto format(const Matrix2x2& m, auto& ctx) const {
        return std::format_to(ctx.out(),
            "[[{}, {}], [{}, {}]]",
            m.data[0][0], m.data[0][1],
            m.data[1][0], m.data[1][1]);
    }
};

int main() {
    Matrix2x2 m{{{{{1.0, 2.0}}, {{3.0, 4.0}}}}};
    std::println("{}", m);
}
```

