// БЫЛО (C++23, компилируется с предупреждениями):
// #include <locale>
// #include <codecvt>
// std::wstring_convert<std::codecvt_utf8<wchar_t>> conv;
// std::wstring wide = conv.from_bytes("hello");  // deprecated!

// СТАЛО (C++26, переносимо):
#include <string>
#include <cstdlib>   // mbstowcs (POSIX/C standard)
#include <cwchar>

// Пример платформенной замены (POSIX):
void narrow_to_wide_example() {
    const char* narrow = "hello";
    std::mbstate_t state{};
    std::size_t len = std::mbsrtowcs(nullptr, &narrow, 0, &state) + 1;
    std::wstring wide(len, L'\0');
    std::mbsrtowcs(wide.data(), &narrow, len, &state);
    // wide теперь содержит L"hello"
}

// Для C++26: std::text_encoding (Модуль 7) — определение кодировки
// Для реальной конвертации: ICU, simdutf или ОС API

#include <atomic>
#include <thread>

// ПЛОХО: volatile НЕ атомарен
// (и составные операции удалены в C++26)
// volatile int shared_counter = 0;
// shared_counter += 1; // ОШИБКА КОМПИЛЯЦИИ в C++26

// ХОРОШО: std::atomic даёт настоящую атомарность
std::atomic<int> shared_counter{0};

void increment_relaxed() {
    // Явный контроль memory order — максимальная производительность
    shared_counter.fetch_add(1, std::memory_order_relaxed);
}

void increment_sequentially_consistent() {
    // Оператор += на atomic — это seq_cst по умолчанию
    shared_counter += 1;
}

// shared_ptr::unique() тоже удалён — используем use_count():
#include <memory>

void migrate_unique() {
    auto ptr = std::make_shared<int>(42);

    // БЫЛО (C++23):
    // if (ptr.unique()) { /* ... */ }  // ОШИБКА в C++26

    // СТАЛО:
    if (ptr.use_count() == 1) {
        // Единственный владелец — но в MT-коде это всё равно racy!
        *ptr = 100;
    }
}

